import React from "react";
import AnimatedSection from "./AnimatedSection";

const NosotrosSection = () => (
  <AnimatedSection style={{ display: "flex", alignItems: "center", gap: "2rem" }}>
    <div style={{ flex: 1, minWidth: "320px" }}>
      <h1
        style={{
          fontSize: "3.5rem",
          fontWeight: "900",
          marginBottom: "1rem",
          color: "#003E73",
        }}
      >
        Nice to meet you
      </h1>
      <p
        style={{
          fontSize: "1.5rem",
          lineHeight: "1.8",
          color: "#003E73",
        }}
      >
        We're John and Jai, co-founders of Hydrant. Our journey started when both us (John, a scientist,
        and Jai, a finance consultant) were trying to solve the same problem on opposite sides of the US. After a
        friend connected us, the rest is history.
      </p>
    </div>

    <div style={{ flex: 1, minWidth: "320px", textAlign: "center" }}>
      <img
        src={require("../../assets/quien-contra-nosotros.jpg")}
        alt="Cargando..."
        style={{
          maxWidth: "100%",
          borderRadius: "1rem",
          boxShadow: "0 0 15px rgba(0,0,0,0.15)",
        }}
      />
    </div>
  </AnimatedSection>
);

export default NosotrosSection;
